Bash(node -e "
const { Pool } = require\('@neondatabase/serverless'\);
const pool = new Pool\({ connectionString: process.env.DATABASE_URL }\);
pool.query\(\\`
  SELECT pp.name, pp.letter_grade, pp.corruption_score, pp.office, pp.state
  FROM politician_profiles pp
  WHERE LOWER\(pp.name\) LIKE '%trump%'
\\`\).then\(r => { console.log\(JSON.stringify\(r.rows, null, 2\)\); pool.end\(\); }\).catch\(e => { console.error\(e\); pool.end\(\); }\);
")

